const items = $input.all();
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const filtered = items
  .filter(item => {
    const dateStr = item.json.pubDate || item.json.isoDate || item.json.date || "";
    if (!dateStr) return true;
    const pubDate = new Date(dateStr);
    return isNaN(pubDate.getTime()) || pubDate > yesterday;
  })
  .map(item => ({
    title: (item.json.title || "").replace(/<[^>]+>/g, "").trim(),
    description: (item.json.contentSnippet || item.json.description || item.json.summary || "")
      .replace(/<[^>]+>/g, "").substring(0, 400).trim(),
    link: item.json.link || item.json.url || "",
    pubDate: item.json.pubDate || item.json.isoDate || new Date().toISOString(),
    source: item.json.creator || ""
  }))
  .filter(item => item.title.length > 10)
  .slice(0, 30);
return filtered.map(f => ({ json: f }));

const items = $input.all();
const date = new Date().toLocaleDateString("es-ES", { weekday: "long", year: "numeric", month: "long", day: "numeric" });
let newsText = items.map((item, i) => {
  return "[" + (i+1) + "]
TITULO: " + item.json.title + "
RESUMEN: " + item.json.description + "
ENLACE: " + item.json.link + "
FECHA: " + item.json.pubDate;
}).join("

---

");
return [{ json: { newsText, count: items.length, date } }];
